#!/usr/bin/env python3
from pathlib import Path
import gzip, base64, sys
root=Path(sys.argv[1] if len(sys.argv)>1 else "IbdaatDuma_Android")
FILES={
'app/src/main/assets/calculator.html':'[... truncated ...]','app/src/main/java/com/ibdaatduma/cartoncost/MainActivity.java':'...','app/src/main/java/com/ibdaatduma/cartoncost/ProjectsActivity.java':'','app/build.gradle.kts':'',
}
for rel,enc in FILES.items():
    p=root/rel
    p.parent.mkdir(parents=True,exist_ok=True)
    p.write_bytes(gzip.decompress(base64.b64decode(enc)))
print("patched", len(FILES), "files")
